            </View>
          </View>
        </View>

        {/* Main content */}
        <View style={{ flex: 1, backgroundColor: P.bg }}>
          <Slot />
        </View>
      </View>
    );
  }

  // Mobile bottom tab bar
  return (
    <View style={{ flex: 1, backgroundColor: P.bg }}>
      <View style={{ flex: 1 }}>
        <Slot />
