import React, { createContext, useContext, useEffect, useState } from 'react';
import { Session, User } from '@supabase/supabase-js';
import { supabase } from '@/utils/supabase';

interface ProfileData {
  role: string;
  full_name?: string;
  avatar_url?: string;
  shop_id?: string;
}

interface AuthContextType {
  user: User | null;
  session: Session | null;
  loading: boolean;
  profile: ProfileData | null;
  signIn: (email: string, password: string) => Promise<{ error: Error | null }>;
  signUp: (email: string, password: string, fullName: string) => Promise<{ error: Error | null }>;
  signOut: () => Promise<void>;
  deleteAccount: () => Promise<{ error: Error | null }>;
  refreshProfile: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  session: null,
  loading: true,
  profile: null,
  signIn: async () => ({ error: null }),
  signUp: async () => ({ error: null }),
  signOut: async () => {},
  deleteAccount: async () => ({ error: null }),
  refreshProfile: async () => {},
});

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);
  const [profile, setProfile] = useState<ProfileData | null>(null);

  const fetchProfile = async (userId: string) => {
    console.log('[Auth] Fetching profile for user:', userId);
    try {
      const { data: profileData } = await supabase
        .from('profiles')
        .select('role, full_name, avatar_url')
        .eq('id', userId)
        .single();
      if (profileData) {
        let shopId: string | undefined;
        if (profileData.role === 'shop_owner' || profileData.role === 'barber') {
          const { data: shop } = await supabase
            .from('barbershops')
            .select('id')
            .eq('owner_profile_id', userId)
            .single();
          if (shop) shopId = shop.id;
        }
        const fullProfile: ProfileData = { ...profileData, shop_id: shopId };
        setProfile(fullProfile);
        console.log('[Auth] Profile fetched:', fullProfile.role, 'shop_id:', shopId);
      }
    } catch (err) {
      console.log('[Auth] fetchProfile exception (non-fatal):', err);
    }
  };

  const refreshProfile = async () => {
    if (user) {
      console.log('[Auth] refreshProfile called');
      await fetchProfile(user.id);
    }
  };

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setUser(session?.user ?? null);
      if (session?.user) {
        fetchProfile(session.user.id).finally(() => setLoading(false));
      } else {
        setLoading(false);
      }
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      setUser(session?.user ?? null);
      if (session?.user) {
        fetchProfile(session.user.id).finally(() => setLoading(false));
      } else {
        setProfile(null);
        setLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

